#include <bits/stdc++.h>
using namespace std;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	for(int i=0; i<n; i++) {
		int x;
		cin>>x;
		int s=0,f=x;
		for(int i=2; i*i<=f; i++) {
			if(x%i==0) {
				s++;
				while(x%i==0) {
					x/=i;
				}
			}
		}
		if(x>1) {
			s++;
		}
		if(s==2) {
			cout<<1;
		} else {
			cout<<0;
		}
		cout<<"\n";
	}
	return 0;
}
